  id: string;
  label: string;
  description?: string;
  icon?: ReactNode;
  keywords?: readonly string[];
  disabled?: boolean;
  // Mention trigger ("@") only: kind tags the pill (data-mention), image = optional avatar URL. Ignored by "/" command triggers.
