// dynamic-notification — Dynamic Island-style AI notification: a resident pill that morphs into a reply bubble.
// `variant` picks the island MATERIAL only (anatomy identical): "surface" = token-driven popover material,
// "glass" = backdrop-blurred dark glass (CSS gradient fallback; <DynamicNotificationGlass> upgrades it to WebGL),
// "liquid" = real refractive glass (<DynamicNotificationLiquid> rasterizes the scene behind the island
// and refracts it through a WebGL lens; CSS backdrop-filter fallback).
export type DynamicNotificationVariant = "surface" | "glass" | "liquid";

// Island lifecycle: collapsed pill → (optional) "thinking" blob while the model is answering
// (`loading` prop) → expanded reply bubble. Derived from `open` + `loading`, never set directly.
export type DynamicNotificationState = "collapsed" | "thinking" | "expanded";

export type DynamicNotificationReplyPayload = {
  value: string;
  clear: () => void;
};

export type DynamicNotificationProps = Omit<ComponentProps<"div">, "onChange"> & {
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean, eventDetails: OpenChangeEventDetails) => void;
  // While true (and open), the island holds the intermediate "thinking" size with the aurora
  // animating — flip it off when the model's answer lands to morph into the full bubble.
  loading?: boolean;
  // Reply field is controllable like ChatComposer's value (uncontrolled by default).
  replyValue?: string;
  defaultReplyValue?: string;
  onReplyValueChange?: (value: string) => void;
  onReply?: (payload: DynamicNotificationReplyPayload) => void | Promise<void>;
  variant?: DynamicNotificationVariant;
  disabled?: boolean;
};

import { useEffect, useRef, useState } from "react";

export type UseCopyToClipboardOptions = {
  text?: string;
  copiedDuration?: number;
  onCopy?: (value: string) => void;
  onCopyError?: (error: unknown) => void;
};

export type UseCopyToClipboardResult = {
  isCopied: boolean;
  copyToClipboard: (value: string) => Promise<boolean>;
  resetCopied: () => void;
};

export type UseCopyToClipboardConfiguredResult = UseCopyToClipboardResult & {
  handleCopy: () => Promise<boolean>;
};

async function copyViaClipboardApi(value: string) {
  if (typeof navigator === "undefined" || !navigator.clipboard?.writeText) return false;

  try {
    await navigator.clipboard.writeText(value);
    return true;
  } catch {
    return false;
  }
}

function copyViaSelection(value: string) {
  if (typeof document === "undefined" || typeof document.execCommand !== "function" || !document.body) return false;

  const activeElement = document.activeElement instanceof HTMLElement ? document.activeElement : null;
  const textarea = document.createElement("textarea");

  textarea.value = value;
  textarea.setAttribute("readonly", "");
  textarea.setAttribute("aria-hidden", "true");
  textarea.style.position = "fixed";
  textarea.style.top = "0";
  textarea.style.left = "0";
  textarea.style.width = "1px";
  textarea.style.height = "1px";
  textarea.style.opacity = "0";
  textarea.style.pointerEvents = "none";

  document.body.appendChild(textarea);

  try {
    textarea.focus();
    textarea.select();
    textarea.setSelectionRange(0, value.length);
    return document.execCommand("copy");
  } catch {
    return false;
  } finally {
    textarea.remove();
    activeElement?.focus({ preventScroll: true });
  }
}

export async function copyTextToClipboard(value: string) {
  if (await copyViaClipboardApi(value)) return true;
  return copyViaSelection(value);
}

export function useCopyToClipboard(options: UseCopyToClipboardOptions & { text: string }): UseCopyToClipboardConfiguredResult;
export function useCopyToClipboard(options?: UseCopyToClipboardOptions): UseCopyToClipboardResult;
export function useCopyToClipboard({ text, copiedDuration = 1200, onCopy, onCopyError }: UseCopyToClipboardOptions = {}) {
  const [isCopied, setIsCopied] = useState(false);
  const resetTimeout = useRef<number | null>(null);

  useEffect(() => {
    const timeoutRef = resetTimeout;

    return () => {
      if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
    };
  }, []);

  function resetCopied() {
    if (resetTimeout.current) window.clearTimeout(resetTimeout.current);
    resetTimeout.current = null;
    setIsCopied(false);
  }

  async function copyToClipboard(value: string) {
    const copied = await copyTextToClipboard(value);
    if (!copied) {
      const error = new Error("Unable to copy text");
      onCopyError?.(error);
      setIsCopied(false);
      return false;
    }

    try {
      onCopy?.(value);
    } catch (error) {
      onCopyError?.(error);
      setIsCopied(false);
      return false;
    }

    setIsCopied(true);
    if (resetTimeout.current) window.clearTimeout(resetTimeout.current);
    resetTimeout.current = window.setTimeout(() => setIsCopied(false), copiedDuration);
    return true;
  }

  function handleCopy() {
    return text !== undefined ? copyToClipboard(text) : Promise.resolve(false);
  }

  return text === undefined ? { isCopied, copyToClipboard, resetCopied } : { isCopied, copyToClipboard, handleCopy, resetCopied };
}

import { type ClassValue, clsx } from "clsx";
import { extendTailwindMerge } from "tailwind-merge";

// type scale = custom `text-*` utils (text-label, text-body, …, see theme.css); tw-merge only knows stock
// sizes, misreads ours as color group — size+color in same cn() then collide in one group, one silently
// dropped (code-diff grid lost text-label, fell to inherited 16px); registering as font-size keeps them independent
const textScale = [
  "micro",
  "caption",
  "label",
  "body",
  "body-lg",
  "heading-1",
  "heading-2",
  "heading-3",
  "heading-4",
  // legacy aliases kept until their call sites migrate to the canonical rungs above
  "meta",
  "title-sm",
  "title-md",
  "title-lg",
  "display",
];

// elevation tiers = custom `shadow-*` utils (shadow-pop/soft/modal, see theme.css); unregistered, tw-merge reads
// them as shadow COLOR and lets them ride alongside a later box-shadow util — a skin's `shadow-(--x)`/`shadow-none`
// then loses to the recipe's `shadow-pop` by CSS order, not argument order (content-surface kept its popover lift)
const shadowScale = ["pop", "soft", "modal"];

const twMerge = extendTailwindMerge({
  extend: {
    classGroups: {
      "font-size": [{ text: textScale }],
      shadow: [{ shadow: shadowScale }],
    },
  },
  // stock Tailwind couples line-height into `text-*` size, so twMerge lets font-size clear a preceding `leading-*`
  // our scale is size-only and default sizes are never used here, so drop that conflict — explicit `leading-*` stands regardless of order
  // w/o this, `leading-5 … text-label` silently drops the leading (code grid fell to 18px row height)
  override: {
    conflictingClassGroups: {
      "font-size": [],
    },
  },
});

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

