  animation-timing-function: var(--ease-emphasized);
}

::view-transition-old(docs-page) {
  animation: aui-view-page-rise-old var(--duration-fast) var(--ease-standard) both;
}

::view-transition-new(docs-page) {
  animation: aui-view-page-rise-new var(--duration-slow) var(--ease-emphasized) both;
}

/* Fallback for engines ignoring root un-naming: shell swaps instantly inside snapshot instead of cross-fading; dead rules when root opt-out applies.
