    circle calc(var(--aui-ripple-r, 0px) * var(--aui-ripple-scale)) at var(--aui-ripple-x, 50%) var(--aui-ripple-y, 50%),
    oklch(from var(--foreground) l c h / calc(0.24 * var(--aui-ripple-alpha))) 0%,
    oklch(from var(--foreground) l c h / calc(0.14 * var(--aui-ripple-alpha))) 42%,
    transparent 70%
