  position: relative;
  overflow: visible;
  isolation: isolate;

  &::before {
    content: "";
    pointer-events: none;
    position: absolute;
    z-index: 2;
    inset-inline: 0.5rem;
    top: 0;
    height: 1px;
    background: linear-gradient(90deg, transparent, oklch(from var(--foreground) l c h / 0.32), transparent);
    opacity: 0;
    transition: opacity var(--duration-fast) var(--ease-standard);
  }

  &:hover::before,
  &:focus-visible::before {
